@@ -0,0 +1,26 @@
+import { NextResponse, NextRequest } from "next/server";
+import { getSession } from "@/lib/session";
+import { searchAddons } from "@/lib/curseforge";
+
+export async function GET(req: NextRequest) {
+  const session = await getSession();
+  if (!session.isLoggedIn) return NextResponse.json({ error: "unauthorized" }, { status: 401 });
+
+  const url = new URL(req.url);
+
+  try {
+    const result = await searchAddons({
+      query: url.searchParams.get("q") || undefined,
+      classId: url.searchParams.get("classId") ? Number(url.searchParams.get("classId")) : undefined,
+      categoryId: url.searchParams.get("categoryId") ? Number(url.searchParams.get("categoryId")) : undefined,
+      gameVersion: url.searchParams.get("gameVersion") || undefined,
+      sortField: url.searchParams.get("sortField") ? Number(url.searchParams.get("sortField")) : undefined,
+      sortOrder: (url.searchParams.get("sortOrder") as "asc" | "desc") || undefined,
+      pageSize: url.searchParams.get("pageSize") ? Number(url.searchParams.get("pageSize")) : undefined,
+      index: url.searchParams.get("index") ? Number(url.searchParams.get("index")) : undefined,
+    });
+    return NextResponse.json(result);
+  } catch {
+    return NextResponse.json({ error: "search failed" }, { status: 500 });
+  }
+}
