@@ -0,0 +1,55 @@
+import { NextResponse, NextRequest } from "next/server";
+import { getSession } from "@/lib/session";
+import { listWorlds } from "@/lib/host";
+import * as bds from "@/lib/bds";
+
+export async function GET(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
+  const session = await getSession();
+  if (!session.isLoggedIn) return NextResponse.json({ error: "unauthorized" }, { status: 401 });
+
+  const { id } = await params;
+  const worlds = await listWorlds();
+  const world = worlds.find((w: any) => w.id === id);
+  if (!world) return NextResponse.json({ error: "server not found" }, { status: 404 });
+  const server = { id: world.id, name: world.name, host: world.ip, apiPort: world.apiPort };
+
+  try {
+    const props = await (bds as any).getProperties(server);
+    const worldName = props["level-name"] || "world";
+    const result = await (bds as any).getWorldAddons(server, worldName);
+    return NextResponse.json(result);
+  } catch {
+    return NextResponse.json({ error: "failed to load addons" }, { status: 500 });
+  }
+}
+
+export async function POST(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
+  const session = await getSession();
+  if (!session.isLoggedIn) return NextResponse.json({ error: "unauthorized" }, { status: 401 });
+
+  const isAdmin = session.role === "admin";
+  const isMod = session.role === "moderator" || isAdmin;
+  if (!isMod) return NextResponse.json({ error: "moderator access required" }, { status: 403 });
+
+  const { id } = await params;
+  const body = await req.json();
+  const { action, uuid, enabled } = body;
+
+  if (action !== "toggle") {
+    return NextResponse.json({ error: `unknown action: ${action}` }, { status: 400 });
+  }
+
+  const worlds = await listWorlds();
+  const world = worlds.find((w: any) => w.id === id);
+  if (!world) return NextResponse.json({ error: "server not found" }, { status: 404 });
+  const server = { id: world.id, name: world.name, host: world.ip, apiPort: world.apiPort };
+
+  try {
+    const props = await (bds as any).getProperties(server);
+    const worldName = props["level-name"] || "world";
+    const result = await (bds as any).toggleAddon(server, { uuid, worldName, enabled });
+    return NextResponse.json(result);
+  } catch {
+    return NextResponse.json({ error: "toggle failed" }, { status: 500 });
+  }
+}
